111:     // Visible for test
112:     public static final String MAX_BUFFER_UTILIZATION_PERCENT_METRIC_NAME = "max-buffer-utilization-percent";
113:     public static final String MAX_CLEAN_TIME_METRIC_NAME = "max-clean-time-secs";
114:     public static final String MAX_COMPACTION_DELAY_METRICS_NAME = "max-compaction-delay-secs";
115: 
116:     private static final String CLEANER_RECOPY_PERCENT_METRIC_NAME = "cleaner-recopy-percent";
117:     private static final String DEAD_THREAD_COUNT_METRIC_NAME = "DeadThreadCount";
