151:      * @param initialConfig Initial configuration parameters for the cleaner. Actual config may be dynamically updated.
152:      * @param logDirs The directories where offset checkpoints reside
153:      * @param logs The map of logs
154:      * @param logDirFailureChannel The channel used to add offline log dirs that may be encountered when cleaning the log
155:      * @param time A way to control the passage of time
156:      */
157:     @SuppressWarnings("this-escape")
158:     public LogCleaner(CleanerConfig initialConfig,
159:                       List<File> logDirs,
160:                       ConcurrentMap<TopicPartition, UnifiedLog> logs,
161:                       LogDirFailureChannel logDirFailureChannel,
162:                       Time time) {
163:         config = initialConfig;
164:         this.logs = logs;
165:         this.logDirFailureChannel = logDirFailureChannel;
166:         cleanerManager = new LogCleanerManager(logDirs, logs, this.logDirFailureChannel);
167:         this.time = time;
168:         throttler = new Throttler(config.maxIoBytesPerSecond, 300, "cleaner-io", "bytes", this.time);
169: 
170:         registerMetrics();
