173:     private void registerMetrics() {
174:         /* a metric to track the maximum utilization of any thread's buffer in the last cleaning */
175:         metricsGroup.newGauge(MAX_BUFFER_UTILIZATION_PERCENT_METRIC_NAME,
176:                 () -> (int) (maxOverCleanerThreads(t -> t.lastStats.bufferUtilization) * 100));
177: 
178:         /* a metric to track the recopy rate of each thread's last cleaning */
179:         metricsGroup.newGauge(CLEANER_RECOPY_PERCENT_METRIC_NAME, () -> {
180:             List<CleanerStats> stats = cleaners.stream().map(t -> t.lastStats).toList();
181:             double recopyRate = (double) stats.stream().mapToLong(stat -> stat.bytesWritten).sum() /
182:                     Math.max(stats.stream().mapToLong(stat -> stat.bytesRead).sum(), 1);
183:             return (int) (100 * recopyRate);
184:         });
185: 
186:         /* a metric to track the maximum cleaning time for the last cleaning from each thread */
187:         metricsGroup.newGauge(MAX_CLEAN_TIME_METRIC_NAME, () -> (int) maxOverCleanerThreads(t -> t.lastStats.elapsedSecs()));
188: 
189:         // a metric to track delay between the time when a log is required to be compacted
190:         // as determined by max compaction lag and the time of last cleaner run.
191:         metricsGroup.newGauge(MAX_COMPACTION_DELAY_METRICS_NAME,
192:                 () -> (int) (maxOverCleanerThreads(t -> (double) t.lastPreCleanStats.maxCompactionDelayMs()) / 1000));
193: 
194:         metricsGroup.newGauge(DEAD_THREAD_COUNT_METRIC_NAME, this::deadThreadCount);
195:     }
