200:     public void startup() {
201:         if (config.numThreads < 1) {
202:             LOG.warn("Invalid value for `log.cleaner.threads`: must be >= 1 starting from Kafka 5.0 since log cleaner" +
203:                     " is always enabled.");
204:         }
205: 
206:         LOG.info("Starting the log cleaner");
207:         IntStream.range(0, config.numThreads).forEach(i -> {
208:             try {
209:                 CleanerThread cleaner = new CleanerThread(i);
210:                 cleaners.add(cleaner);
211:                 cleaner.start();
212:             } catch (NoSuchAlgorithmException e) {
213:                 throw new RuntimeException(e);
214:             }
215:         });
216:     }
