218:     /**
219:      * Stop the background cleaner threads.
220:      */
221:     private void shutdownCleaners() {
222:         LOG.info("Shutting down the log cleaner.");
223:         cleaners.forEach(thread -> {
224:             try {
225:                 thread.shutdown();
226:             } catch (InterruptedException e) {
227:                 throw new RuntimeException(e);
228:             }
229:         });
230:         cleaners.clear();
231:     }
