374:     /**
375:      * For testing, a way to know when work has completed. This method waits until the
376:      * cleaner has processed up to the given offset on the specified topic/partition.
377:      *
378:      * @param topicPartition The topic and partition to be cleaned
379:      * @param offset The first dirty offset that the cleaner doesn't have to clean
380:      * @param maxWaitMs The maximum time in ms to wait for cleaner
381:      *
382:      * @return A boolean indicating whether the work has completed before timeout
383:      */
384:     public boolean awaitCleaned(TopicPartition topicPartition, long offset, long maxWaitMs) throws InterruptedException {
385:         long remainingWaitMs = maxWaitMs;
386:         while (!isCleaned(topicPartition, offset) && remainingWaitMs > 0) {
387:             long sleepTime = Math.min(100, remainingWaitMs);
388:             Thread.sleep(sleepTime);
389:             remainingWaitMs -= sleepTime;
390:         }
391:         return isCleaned(topicPartition, offset);
392:     }
