463:     /**
464:      * The cleaner threads do the actual log cleaning. Each thread processes does its cleaning repeatedly by
465:      * choosing the dirtiest log, cleaning it, and then swapping in the cleaned segments.
466:      */
467:     public class CleanerThread extends ShutdownableThread {
468:         private final Logger logger = new LogContext(logPrefix).logger(CleanerThread.class);
469: 
470:         private final Cleaner cleaner;
471: 
472:         private volatile CleanerStats lastStats = new CleanerStats(Time.SYSTEM);
473:         private volatile PreCleanStats lastPreCleanStats = new PreCleanStats();
474: 
475:         @SuppressWarnings("this-escape")
476:         public CleanerThread(int threadId) throws NoSuchAlgorithmException {
477:             super("kafka-log-cleaner-thread-" + threadId, false);
478: 
479:             cleaner = new Cleaner(
480:                     threadId,
481:                     new SkimpyOffsetMap((int) Math.min(config.dedupeBufferSize / config.numThreads, Integer.MAX_VALUE), config.hashAlgorithm()),
482:                     config.ioBufferSize / config.numThreads / 2,
483:                     config.maxMessageSize,
484:                     config.dedupeBufferLoadFactor,
485:                     throttler,
486:                     time,
487:                     this::checkDone
488:             );
489: 
490:             if (config.dedupeBufferSize / config.numThreads > Integer.MAX_VALUE) {
491:                 logger.warn("Cannot use more than 2G of cleaner buffer space per cleaner thread, ignoring excess buffer space...");
492:             }
493:         }
494: 
495:         /**
496:          *  Check if the cleaning for a partition is aborted. If so, throw an exception.
497:          *
498:          *  @param topicPartition The topic and partition to check
499:          */
500:         private void checkDone(TopicPartition topicPartition) {
501:             if (!isRunning()) {
502:                 throw new ThreadShutdownException();
503:             }
504: 
505:             cleanerManager.checkCleaningAborted(topicPartition);
506:         }
507: 
508:         /**
509:          * The main loop for the cleaner thread.
510:          * Clean a log if there is a dirty log available, otherwise sleep for a bit.
511:          */
512:         @Override
513:         public void doWork() {
514:             boolean cleaned = tryCleanFilthiestLog();
515:             if (!cleaned) {
516:                 try {
517:                     pause(config.backoffMs, TimeUnit.MILLISECONDS);
518:                 } catch (InterruptedException e) {
519:                     throw new RuntimeException(e);
520:                 }
521:             }
522: 
523:             cleanerManager.maintainUncleanablePartitions();
524:         }
525: 
526:         public CleanerStats lastStats() {
527:             return lastStats;
528:         }
529: 
530:         public void setLastStats(CleanerStats lastStats) {
531:             this.lastStats = lastStats;
532:         }
533: 
534:         public PreCleanStats lastPreCleanStats() {
535:             return lastPreCleanStats;
536:         }
537: 
538:         /**
539:          * Cleans a log if there is a dirty log available.
540:          *
541:          * @return whether a log was cleaned
542:          */
543:         private boolean tryCleanFilthiestLog() {
544:             try {
545:                 return cleanFilthiestLog();
546:             } catch (LogCleaningException e) {
547:                 logger.warn("Unexpected exception thrown when cleaning log {}. Marking its partition ({}) as uncleanable", e.log, e.log.topicPartition(), e);
548:                 cleanerManager.markPartitionUncleanable(e.log.parentDir(), e.log.topicPartition());
549: 
550:                 return false;
551:             }
552:         }
553: 
554:         private boolean cleanFilthiestLog() throws LogCleaningException {
555:             PreCleanStats preCleanStats = new PreCleanStats();
556:             Optional<LogToClean> ltc = cleanerManager.grabFilthiestCompactedLog(time, preCleanStats);
557:             boolean cleaned;
558: 
559:             if (ltc.isEmpty()) {
560:                 cleaned = false;
561:             } else {
562:                 // there's a log, clean it
563:                 this.lastPreCleanStats = preCleanStats;
564:                 LogToClean cleanable = ltc.get();
565:                 try {
566:                     cleanLog(cleanable);
567:                     cleaned = true;
568:                 } catch (ThreadShutdownException e) {
569:                     throw e;
570:                 } catch (Exception e) {
571:                     throw new LogCleaningException(cleanable.log(), e.getMessage(), e);
572:                 }
573:             }
574: 
575:             Map<TopicPartition, UnifiedLog> deletable = cleanerManager.deletableLogs();
576:             try {
577:                 deletable.forEach((topicPartition, log) -> {
578:                     try {
579:                         log.deleteOldSegments();
580:                     } catch (ThreadShutdownException e) {
581:                         throw e;
582:                     } catch (Exception e) {
583:                         throw new LogCleaningException(log, e.getMessage(), e);
584:                     }
585:                 });
586:             } finally {
587:                 cleanerManager.doneDeleting(deletable.keySet().stream().toList());
588:             }
589: 
590:             return cleaned;
591:         }
592: 
593:         private void cleanLog(LogToClean cleanable) throws DigestException {
594:             long startOffset = cleanable.firstDirtyOffset();
595:             long endOffset = startOffset;
596:             try {
597:                 Map.Entry<Long, CleanerStats> entry = cleaner.clean(cleanable);
598:                 endOffset = entry.getKey();
599:                 recordStats(cleaner.id(), cleanable.log().name(), startOffset, endOffset, entry.getValue());
600:             } catch (LogCleaningAbortedException ignored) {
601:                 // task can be aborted, let it go.
602:             } catch (KafkaStorageException ignored) {
603:                 // partition is already offline. let it go.
604:             } catch (IOException e) {
605:                 String logDirectory = cleanable.log().parentDir();
606:                 String msg = String.format("Failed to clean up log for %s in dir %s due to IOException", cleanable.topicPartition(), logDirectory);
607:                 logDirFailureChannel.maybeAddOfflineLogDir(logDirectory, msg, e);
608:             } finally {
609:                 cleanerManager.doneCleaning(cleanable.topicPartition(), cleanable.log().parentDirFile(), endOffset);
610:             }
611:         }
612: 
613:         /**
614:          * Log out statistics on a single run of the cleaner.
615:          *
616:          * @param id The cleaner thread id
617:          * @param name The cleaned log name
618:          * @param from The cleaned offset that is the first dirty offset to begin
619:          * @param to The cleaned offset that is the first not cleaned offset to end
620:          * @param stats The statistics for this round of cleaning
621:          */
622:         private void recordStats(int id, String name, long from, long to, CleanerStats stats) {
623:             this.lastStats = stats;
624:             String message = String.format("%n\tLog cleaner thread %d cleaned log %s (dirty section = [%d, %d])%n", id, name, from, to) +
625:                         String.format("\t%,.1f MB of log processed in %,.1f seconds (%,.1f MB/sec).%n", mb(stats.bytesRead),
626:                                 stats.elapsedSecs(),
627:                                 mb(stats.bytesRead / stats.elapsedSecs())) +
628:                         String.format("\tIndexed %,.1f MB in %.1f seconds (%,.1f Mb/sec, %.1f%% of total time)%n", mb(stats.mapBytesRead),
629:                                 stats.elapsedIndexSecs(),
630:                                 mb(stats.mapBytesRead) / stats.elapsedIndexSecs(),
631:                                 100 * stats.elapsedIndexSecs() / stats.elapsedSecs()) +
632:                         String.format("\tBuffer utilization: %.1f%%%n", 100 * stats.bufferUtilization) +
633:                         String.format("\tCleaned %,.1f MB in %.1f seconds (%,.1f Mb/sec, %.1f%% of total time)%n", mb(stats.bytesRead),
634:                                 stats.elapsedSecs() - stats.elapsedIndexSecs(),
635:                                 mb(stats.bytesRead) / (stats.elapsedSecs() - stats.elapsedIndexSecs()), 100 * (stats.elapsedSecs() - stats.elapsedIndexSecs()) / stats.elapsedSecs()) +
636:                         String.format("\tStart size: %,.1f MB (%,d messages)%n", mb(stats.bytesRead), stats.messagesRead) +
637:                         String.format("\tEnd size: %,.1f MB (%,d messages)%n", mb(stats.bytesWritten), stats.messagesWritten) +
638:                         String.format("\t%.1f%% size reduction (%.1f%% fewer messages)%n", 100.0 * (1.0 - Long.valueOf(stats.bytesWritten).doubleValue() / stats.bytesRead),
639:                                 100.0 * (1.0 - Long.valueOf(stats.messagesWritten).doubleValue() / stats.messagesRead));
640:             logger.info(message);
641:             if (lastPreCleanStats.delayedPartitions() > 0) {
642:                 logger.info("\tCleanable partitions: {}, Delayed partitions: {}, max delay: {}",
643:                         lastPreCleanStats.cleanablePartitions(), lastPreCleanStats.delayedPartitions(), lastPreCleanStats.maxCompactionDelayMs());
644:             }
645:             if (stats.invalidMessagesRead > 0) {
646:                 logger.warn("\tFound {} invalid messages during compaction.", stats.invalidMessagesRead);
647:             }
648:         }
649: 
650:         private double mb(double bytes) {
651:             return bytes / (1024 * 1024);
652:         }
653:     }
654: }
