47: /**
48:  * This class holds the actual logic for cleaning a log.
49:  */
50: public class Cleaner {
51:     private final BufferSupplier decompressionBufferSupplier = BufferSupplier.create();
52: 
53:     private final Logger logger;
54:     private final int id;
55:     private final OffsetMap offsetMap;
56:     private final int ioBufferSize;
57:     private final int maxIoBufferSize;
58:     private final double dupBufferLoadFactor;
59:     private final Throttler throttler;
60:     private final Time time;
61:     private final Consumer<TopicPartition> checkDone;
62: 
63:     /**
64:      * Buffer used for read i/o
65:      */
66:     private ByteBuffer readBuffer;
67: 
68:     /**
69:      * Buffer used for write i/o
70:      */
71:     private ByteBuffer writeBuffer;
72: 
73:     /**
74:      *
75:      * @param id An identifier used for logging
76:      * @param offsetMap The map used for deduplication
77:      * @param ioBufferSize The size of the buffers to use. Memory usage will be 2x this number as there is a read and write buffer.
78:      * @param maxIoBufferSize The maximum size of a message that can appear in the log
79:      * @param dupBufferLoadFactor The maximum percent full for the deduplication buffer
80:      * @param throttler The throttler instance to use for limiting I/O rate
81:      * @param time The time instance
82:      * @param checkDone Check if the cleaning for a partition is finished or aborted
83:      */
84:     public Cleaner(int id,
85:                    OffsetMap offsetMap,
86:                    int ioBufferSize,
87:                    int maxIoBufferSize,
88:                    double dupBufferLoadFactor,
89:                    Throttler throttler,
90:                    Time time,
91:                    Consumer<TopicPartition> checkDone) {
92:         this.id = id;
93:         this.offsetMap = offsetMap;
94:         this.ioBufferSize = ioBufferSize;
95:         this.maxIoBufferSize = maxIoBufferSize;
96:         this.dupBufferLoadFactor = dupBufferLoadFactor;
97:         this.throttler = throttler;
98:         this.time = time;
99:         this.checkDone = checkDone;
100:         logger = new LogContext("Cleaner " + id + ": ").logger(Cleaner.class);
101: 
102:         readBuffer = ByteBuffer.allocate(ioBufferSize);
103:         writeBuffer = ByteBuffer.allocate(ioBufferSize);
104: 
105:         assert offsetMap.slots() * dupBufferLoadFactor > 1 :
106:                 "offset map is too small to fit in even a single message, so log cleaning will never make progress. " +
107:                         "You can increase log.cleaner.dedupe.buffer.size or decrease log.cleaner.threads";
108:     }
109: 
110:     public int id() {
111:         return id;
112:     }
113: 
114:     // Only for testing
115:     public OffsetMap offsetMap() {
116:         return offsetMap;
117:     }
118: 
119:     /**
120:      * Clean the given log.
121:      *
122:      * @param cleanable The log to be cleaned
123:      *
124:      * @return The first offset not cleaned and the statistics for this round of cleaning
125:      */
126:     public Map.Entry<Long, CleanerStats> clean(LogToClean cleanable) throws IOException, DigestException {
127:         return doClean(cleanable, time.milliseconds());
128:     }
129: 
130:     /**
131:      * Clean the given log.
132:      *
133:      * @param cleanable The log to be cleaned
134:      * @param currentTime The current timestamp for doing cleaning
135:      *
136:      * @return The first offset not cleaned and the statistics for this round of cleaning
137:      * */
138:     public Map.Entry<Long, CleanerStats> doClean(LogToClean cleanable, long currentTime) throws IOException, DigestException {
139:         UnifiedLog log = cleanable.log();
140: 
141:         logger.info("Beginning cleaning of log {}", log.name());
142: 
143:         // figure out the timestamp below which it is safe to remove delete tombstones
144:         // this position is defined to be a configurable time beneath the last modified time of the last clean segment
145:         // this timestamp is only used on the older message formats older than MAGIC_VALUE_V2
146:         List<LogSegment> segments = log.logSegments(0, cleanable.firstDirtyOffset());
147:         long legacyDeleteHorizonMs = segments.isEmpty()
148:                 ? 0L
149:                 : segments.get(segments.size() - 1).lastModified() - log.config().deleteRetentionMs;
150: 
151:         CleanerStats stats = new CleanerStats(Time.SYSTEM);
152: 
153:         // build the offset map
154:         logger.info("Building offset map for {}...", log.name());
155:         long upperBoundOffset = cleanable.firstUncleanableOffset();
156:         buildOffsetMap(log, cleanable.firstDirtyOffset(), upperBoundOffset, offsetMap, stats);
157:         long endOffset = offsetMap.latestOffset() + 1;
158:         stats.indexDone();
159: 
160:         // determine the timestamp up to which the log will be cleaned
161:         // this is the lower of the last active segment and the compaction lag
162:         segments = log.logSegments(0, cleanable.firstUncleanableOffset());
163:         long cleanableHorizonMs = segments.isEmpty()
164:                 ? 0L
165:                 : segments.get(segments.size() - 1).lastModified();
166: 
167:         // group the segments and clean the groups
168:         logger.info("Cleaning log {} (cleaning prior to {}, discarding tombstones prior to upper bound deletion horizon {})...",
169:                 log.name(), new Date(cleanableHorizonMs), new Date(legacyDeleteHorizonMs));
170:         CleanedTransactionMetadata transactionMetadata = new CleanedTransactionMetadata();
171: 
172:         List<List<LogSegment>> groupedSegments = groupSegmentsBySize(
173:                 log.logSegments(0, endOffset),
174:                 log.config().segmentSize(),
175:                 log.config().maxIndexSize,
176:                 cleanable.firstUncleanableOffset()
177:         );
178: 
179:         for (List<LogSegment> group : groupedSegments) {
180:             cleanSegments(log, group, offsetMap, currentTime, stats, transactionMetadata, legacyDeleteHorizonMs, upperBoundOffset);
181:         }
182: 
183:         // record buffer utilization
184:         stats.bufferUtilization = offsetMap.utilization();
185: 
186:         stats.allDone();
187: 
188:         return Map.entry(endOffset, stats);
189:     }
190: 
191:     /**
192:      * Clean a group of segments into a single replacement segment.
193:      *
194:      * @param log The log being cleaned
195:      * @param segments The group of segments being cleaned
196:      * @param map The offset map to use for cleaning segments
197:      * @param currentTime The current time in milliseconds
198:      * @param stats Collector for cleaning statistics
199:      * @param transactionMetadata State of ongoing transactions which is carried between the cleaning
200:      *                            of the grouped segments
201:      * @param legacyDeleteHorizonMs The delete horizon used for tombstones whose version is less than 2
202:      * @param upperBoundOffsetOfCleaningRound The upper bound offset of this round of cleaning
203:      */
204:     @SuppressWarnings("finally")
205:     public void cleanSegments(UnifiedLog log,
206:                                List<LogSegment> segments,
207:                                OffsetMap map,
208:                                long currentTime,
209:                                CleanerStats stats,
210:                                CleanedTransactionMetadata transactionMetadata,
211:                                long legacyDeleteHorizonMs,
212:                                long upperBoundOffsetOfCleaningRound) throws IOException {
213:         // create a new segment with a suffix appended to the name of the log and indexes
214:         LogSegment cleaned = UnifiedLog.createNewCleanedSegment(log.dir(), log.config(), segments.get(0).baseOffset());
215:         transactionMetadata.setCleanedIndex(Optional.of(cleaned.txnIndex()));
216: 
217:         try {
218:             // clean segments into the new destination segment
219:             Iterator<LogSegment> iter = segments.iterator();
220:             Optional<LogSegment> currentSegmentOpt = Optional.of(iter.next());
221:             Map<Long, LastRecord> lastOffsetOfActiveProducers = log.lastRecordsOfActiveProducers();
222: 
223:             while (currentSegmentOpt.isPresent()) {
224:                 LogSegment currentSegment = currentSegmentOpt.get();
225:                 Optional<LogSegment> nextSegmentOpt = iter.hasNext() ? Optional.of(iter.next()) : Optional.empty();
226: 
227:                 // Note that it is important to collect aborted transactions from the full log segment
228:                 // range since we need to rebuild the full transaction index for the new segment.
229:                 long startOffset = currentSegment.baseOffset();
230:                 long upperBoundOffset = nextSegmentOpt.map(LogSegment::baseOffset).orElse(currentSegment.readNextOffset());
231:                 List<AbortedTxn> abortedTransactions = log.collectAbortedTransactions(startOffset, upperBoundOffset);
232:                 transactionMetadata.addAbortedTransactions(abortedTransactions);
233: 
234:                 boolean retainLegacyDeletesAndTxnMarkers = currentSegment.lastModified() > legacyDeleteHorizonMs;
235:                 logger.info(
236:                         "Cleaning {} in log {} into {} with an upper bound deletion horizon {} computed from " +
237:                         "the segment last modified time of {},{} deletes.",
238:                         currentSegment, log.name(), cleaned.baseOffset(), legacyDeleteHorizonMs, currentSegment.lastModified(),
239:                         retainLegacyDeletesAndTxnMarkers ? "retaining" : "discarding"
240:                 );
241: 
242:                 try {
243:                     cleanInto(
244:                             log.topicPartition(),
245:                             currentSegment.log(),
246:                             cleaned,
247:                             map,
248:                             retainLegacyDeletesAndTxnMarkers,
249:                             log.config().deleteRetentionMs,
250:                             log.config().maxMessageSize(),
251:                             transactionMetadata,
252:                             lastOffsetOfActiveProducers,
253:                             upperBoundOffsetOfCleaningRound,
254:                             stats,
255:                             currentTime
256:                     );
257:                 } catch (LogSegmentOffsetOverflowException e) {
258:                     // Split the current segment. It's also safest to abort the current cleaning process, so that we retry from
259:                     // scratch once the split is complete.
260:                     logger.info("Caught segment overflow error during cleaning: {}", e.getMessage());
261:                     log.splitOverflowedSegment(currentSegment);
262:                     throw new LogCleaningAbortedException();
263:                 }
264:                 currentSegmentOpt = nextSegmentOpt;
265:             }
266: 
267:             cleaned.onBecomeInactiveSegment();
268:             // flush new segment to disk before swap
269:             cleaned.flush();
270: 
271:             // update the modification date to retain the last modified date of the original files
272:             long modified = segments.get(segments.size() - 1).lastModified();
273:             cleaned.setLastModified(modified);
274: 
275:             // swap in new segment
276:             logger.info("Swapping in cleaned segment {} for segment(s) {} in log {}", cleaned, segments, log);
277:             log.replaceSegments(List.of(cleaned), segments);
278:         } catch (LogCleaningAbortedException e) {
279:             try {
280:                 cleaned.deleteIfExists();
281:             } catch (Exception deleteException) {
282:                 e.addSuppressed(deleteException);
283:             } finally {
284:                 throw e;
285:             }
286:         }
287:     }
