{"content":"300:      * @param transactionMetadata The state of ongoing transactions which is carried between the cleaning of the grouped segments
301:      * @param lastRecordsOfActiveProducers The active producers and its last data offset
302:      * @param upperBoundOffsetOfCleaningRound Next offset of the last batch in the source segment
303:      * @param stats Collector for cleaning statistics
304:      * @param currentTime The time at which the clean was initiated
305:      */
306:     private void cleanInto(TopicPartition topicPartition,
307:                            FileRecords sourceRecords,
308:                            LogSegment dest,
309:                            OffsetMap map,
310:                            boolean retainLegacyDeletesAndTxnMarkers,
311:                            long deleteRetentionMs,
312:                            int maxLogMessageSize,
313:                            CleanedTransactionMetadata transactionMetadata,
314:                            Map<Long, LastRecord> lastRecordsOfActiveProducers,
315:                            long upperBoundOffsetOfCleaningRound,
316:                            CleanerStats stats,
317:                            long currentTime) throws IOException {
318:         MemoryRecords.RecordFilter logCleanerFilter = new MemoryRecords.RecordFilter(currentTime, deleteRetentionMs) {
319:             private boolean discardBatchRecords;
320: 
321:             @Override
322:             public BatchRetentionResult checkBatchRetention(RecordBatch batch) {
323:                 // we piggy-back on the tombstone retention logic to delay deletion of transaction markers.
324:                 // note that we will never delete a marker until all the records from that transaction are removed.
325:                 boolean canDiscardBatch = shouldDiscardBatch(batch, transactionMetadata);
326: 
327:                 if (batch.isControlBatch()) {
328:                     discardBatchRecords = canDiscardBatch && batch.deleteHorizonMs().isPresent() && batch.deleteHorizonMs().getAsLong() <= this.currentTime;
329:                 } else {
330:                     discardBatchRecords = canDiscardBatch;
331:                 }
332: 
333:                 // We retain the batch in order to preserve the state of active producers. There are three cases:
334:                 // 1) The producer is no longer active, which means we can delete all records for that producer.
335:                 // 2) The producer is still active and has a last data offset. We retain the batch that contains
336:                 //    this offset since it also contains the last sequence number for this producer.
337:                 // 3) The last entry in the log is a transaction marker. We retain this marker since it has the
338:                 //    last producer epoch, which is needed to ensure fencing.
339:                 boolean isBatchLastRecordOfProducer = Optional.ofNullable(lastRecordsOfActiveProducers.get(batch.producerId()))
340:                         .map(lastRecord -> {
341:                             if (lastRecord.lastDataOffset.isPresent()) {
342:                                 return batch.lastOffset() == lastRecord.lastDataOffset.getAsLong();
343:                             } else {
344:                                 return batch.isControlBatch() && batch.producerEpoch() == lastRecord.producerEpoch;
345:                             }
346:                         })
347:                         .orElse(false);
348: 
349:                 BatchRetention batchRetention;
350:                 if (batch.hasProducerId() && isBatchLastRecordOfProducer)
351:                     batchRetention = BatchRetention.RETAIN_EMPTY;
352:                 else if (batch.nextOffset() == upperBoundOffsetOfCleaningRound) {
353:                     // retain the last batch of the cleaning round, even if it's empty, so that last offset information
354:                     // is not lost after cleaning.
355:                     batchRetention = BatchRetention.RETAIN_EMPTY;
356:                 } else if (discardBatchRecords)
357:                     batchRetention = BatchRetention.DELETE;
358:                 else
359:                     batchRetention = BatchRetention.DELETE_EMPTY;
360: 
361:                 return new BatchRetentionResult(batchRetention, canDiscardBatch && batch.isControlBatch());
362:             }
363: 
364:             @Override
365:             public boolean shouldRetainRecord(RecordBatch batch, Record record) {
366:                 if (discardBatchRecords) {
367:                     // The batch is only retained to preserve producer sequence information; the records can be removed
368:                     return false;
369:                 } else if (batch.isControlBatch()) {
370:                     return true;
371:                 } else {
372:                     try {
373:                         return Cleaner.this.shouldRetainRecord(map, retainLegacyDeletesAndTxnMarkers, batch, record, stats, currentTime);
374:                     } catch (DigestException e) {
375:                         throw new RuntimeException(e);
376:                     }
377:                 }
378:             }
379:         };
380: 
381:         int position = 0;
382:         while (position < sourceRecords.sizeInBytes()) {
383:             checkDone.accept(topicPartition);
384:             // read a chunk of messages and copy any that are to be retained to the write buffer to be written out
385:             readBuffer.clear();
386:             writeBuffer.clear();
387: 
388:             sourceRecords.readInto(readBuffer, position);
389:             MemoryRecords records = MemoryRecords.readableRecords(readBuffer);
390:             throttler.maybeThrottle(records.sizeInBytes());
391:             MemoryRecords.FilterResult result = records.filterTo(logCleanerFilter, writeBuffer, decompressionBufferSupplier);
392: 
393:             stats.readMessages(result.messagesRead(), result.bytesRead());
394:             stats.recopyMessages(result.messagesRetained(), result.bytesRetained());
395: 
396:             position += result.bytesRead();
397: 
398:             // if any messages are to be retained, write them out
399:             ByteBuffer outputBuffer = result.outputBuffer();
400:             if (outputBuffer.position() > 0) {
401:                 outputBuffer.flip();
402:                 MemoryRecords retained = MemoryRecords.readableRecords(outputBuffer);
403:                 // it's OK not to hold the Log's lock in this case, because this segment is only accessed by other threads
404:                 // after `Log.replaceSegments` (which acquires the lock) is called
405:                 dest.append(result.maxOffset(), retained);
406:                 throttler.maybeThrottle(outputBuffer.limit());
407:             }
408: 
409:             // if we read bytes but didn't get even one complete batch, our I/O buffer is too small, grow it and try again
410:             // `result.bytesRead` contains bytes from `messagesRead` and any discarded batches.
411:             if (readBuffer.limit() > 0 && result.bytesRead() == 0)
412:                 growBuffersOrFail(sourceRecords, position, maxLogMessageSize, records);
413:         }
414:         restoreBuffers();
415:     }
