464:     /**
465:      * Check if a batch should be discarded by cleaned transaction state.
466:      *
467:      * @param batch The batch of records to check
468:      * @param transactionMetadata The maintained transaction state about cleaning
469:      *
470:      * @return if the batch can be discarded
471:      */
472:     private boolean shouldDiscardBatch(RecordBatch batch,
473:                                        CleanedTransactionMetadata transactionMetadata) {
474:         if (batch.isControlBatch())
475:             return transactionMetadata.onControlBatchRead(batch);
476:         else
477:             return transactionMetadata.onBatchRead(batch);
478:     }
