529:     /**
530:      * Double the I/O buffer capacity.
531:      *
532:      * @param maxLogMessageSize The maximum record size in bytes allowed
533:      */
534:     private void growBuffers(int maxLogMessageSize) {
535:         int maxBufferSize = Math.max(maxLogMessageSize, maxIoBufferSize);
536:         if (readBuffer.capacity() >= maxBufferSize || writeBuffer.capacity() >= maxBufferSize)
537:             throw new IllegalStateException("This log contains a message larger than maximum allowable size of " + maxBufferSize + ".");
538:         int newSize = Math.min(readBuffer.capacity() * 2, maxBufferSize);
539:         logger.info("Growing cleaner I/O buffers from {} bytes to {} bytes.", readBuffer.capacity(), newSize);
540:         readBuffer = ByteBuffer.allocate(newSize);
541:         writeBuffer = ByteBuffer.allocate(newSize);
542:     }
543: 
544:     /**
545:      * Restore the I/O buffer capacity to its original size.
546:      */
547:     private void restoreBuffers() {
548:         if (readBuffer.capacity() > ioBufferSize)
549:             readBuffer = ByteBuffer.allocate(ioBufferSize);
550:         if (writeBuffer.capacity() > ioBufferSize)
551:             writeBuffer = ByteBuffer.allocate(ioBufferSize);
552:     }
