554:     /**
555:      * Group the segments in a log into groups totaling less than a given size. the size is enforced separately for the log data and the index data.
556:      * We collect a group of such segments together into a single destination segment.
557:      * This prevents segment sizes from shrinking too much.
558:      *
559:      * @param segments The log segments to group
560:      * @param maxSize the maximum size in bytes for the total of all log data in a group
561:      * @param maxIndexSize the maximum size in bytes for the total of all index data in a group
562:      * @param firstUncleanableOffset The upper(exclusive) offset to clean to
563:      *
564:      * @return A list of grouped segments
565:      */
566:     public List<List<LogSegment>> groupSegmentsBySize(List<LogSegment> segments, int maxSize, int maxIndexSize, long firstUncleanableOffset) throws IOException {
567:         List<List<LogSegment>> grouped = new ArrayList<>();
568: 
569:         while (!segments.isEmpty()) {
570:             List<LogSegment> group = new ArrayList<>();
571:             group.add(segments.get(0));
572: 
573:             long logSize = segments.get(0).size();
574:             long indexSize = segments.get(0).offsetIndex().sizeInBytes();
575:             long timeIndexSize = segments.get(0).timeIndex().sizeInBytes();
576: 
577:             segments = segments.subList(1, segments.size());
578: 
579:             while (!segments.isEmpty() &&
580:                     logSize + segments.get(0).size() <= maxSize &&
581:                     indexSize + segments.get(0).offsetIndex().sizeInBytes() <= maxIndexSize &&
582:                     timeIndexSize + segments.get(0).timeIndex().sizeInBytes() <= maxIndexSize &&
583:                     //if first segment size is 0, we don't need to do the index offset range check.
584:                     //this will avoid empty log left every 2^31 message.
585:                     (segments.get(0).size() == 0 ||
586:                             lastOffsetForFirstSegment(segments, firstUncleanableOffset) - group.get(group.size() - 1).baseOffset() <= Integer.MAX_VALUE)) {
587:                 group.add(0, segments.get(0));
588:                 logSize += segments.get(0).size();
589:                 indexSize += segments.get(0).offsetIndex().sizeInBytes();
590:                 timeIndexSize += segments.get(0).timeIndex().sizeInBytes();
591:                 segments = segments.subList(1, segments.size());
592:             }
593: 
594:             Collections.reverse(group);
595:             grouped.add(0, group);
596:         }
597: 
598:         Collections.reverse(grouped);
599: 
600:         return grouped;
601:     }
