603:     /**
604:      * We want to get the last offset in the first log segment in segs.
605:      * LogSegment.nextOffset() gives the exact last offset in a segment, but can be expensive since it requires
606:      * scanning the segment from the last index entry.
607:      * Therefore, we estimate the last offset of the first log segment by using
608:      * the base offset of the next segment in the list.
609:      * If the next segment doesn't exist, first Uncleanable Offset will be used.
610:      *
611:      * @param segs Remaining segments to group
612:      * @param firstUncleanableOffset The upper(exclusive) offset to clean to
613:      * @return The estimated last offset for the first segment in segs
614:      */
615:     private long lastOffsetForFirstSegment(List<LogSegment> segs, long firstUncleanableOffset) {
616:         if (segs.size() > 1) {
617:             /* if there is a next segment, use its base offset as the bounding offset to guarantee we know
618:              * the worst case offset */
619:             return segs.get(1).baseOffset() - 1;
620:         } else {
621:             //for the last segment in the list, use the first uncleanable offset.
622:             return firstUncleanableOffset - 1;
623:         }
624:     }
