626:     /**
627:      * Build a map of key_hash => offset for the keys in the cleanable dirty portion of the log to use in cleaning.
628:      *
629:      * @param log The log to use
630:      * @param start The offset at which dirty messages begin
631:      * @param end The ending offset for the map that is being built
632:      * @param map The map in which to store the mappings
633:      * @param stats Collector for cleaning statistics
634:      */
635:     public void buildOffsetMap(UnifiedLog log,
636:                                long start,
637:                                long end,
638:                                OffsetMap map,
639:                                CleanerStats stats) throws IOException, DigestException {
640:         map.clear();
641:         List<LogSegment> dirty = log.logSegments(start, end);
642:         List<Long> nextSegmentStartOffsets = new ArrayList<>();
643:         if (!dirty.isEmpty()) {
644:             for (int i = 1; i < dirty.size(); i++) {
645:                 nextSegmentStartOffsets.add(dirty.get(i).baseOffset());
646:             }
647:             nextSegmentStartOffsets.add(end);
648:         }
649:         logger.info("Building offset map for log {} for {} segments in offset range [{}, {}).", log.name(), dirty.size(), start, end);
650: 
651:         CleanedTransactionMetadata transactionMetadata = new CleanedTransactionMetadata();
652:         List<AbortedTxn> abortedTransactions = log.collectAbortedTransactions(start, end);
653:         transactionMetadata.addAbortedTransactions(abortedTransactions);
654: 
655:         // Add all the cleanable dirty segments. We must take at least map.slots * load_factor,
656:         // but we may be able to fit more (if there is lots of duplication in the dirty section of the log)
657:         boolean full = false;
658:         for (int i = 0; i < dirty.size() && !full; i++) {
659:             LogSegment segment = dirty.get(i);
660:             long nextSegmentStartOffset = nextSegmentStartOffsets.get(i);
661: 
662:             checkDone.accept(log.topicPartition());
663: 
664:             full = buildOffsetMapForSegment(
665:                     log.topicPartition(),
666:                     segment,
667:                     map,
668:                     start,
669:                     nextSegmentStartOffset,
670:                     log.config().maxMessageSize(),
671:                     transactionMetadata,
672:                     stats
673:             );
674:             if (full) {
675:                 logger.debug("Offset map is full, {} segments fully mapped, segment with base offset {} is partially mapped",
676:                         dirty.indexOf(segment), segment.baseOffset());
677:             }
678:         }
679: 
680:         logger.info("Offset map for log {} complete.", log.name());
681:     }
