49: /**
50:  * This class manages the state (see {@link LogCleaningState}) of each partition being cleaned.
51:  * <ul>
52:  * <li>1. None                    : No cleaning state in a TopicPartition. In this state, it can become LogCleaningInProgress
53:  *                                or LogCleaningPaused(1). Valid previous state are LogCleaningInProgress and LogCleaningPaused(1)</li>
54:  * <li>2. LogCleaningInProgress   : The cleaning is currently in progress. In this state, it can become None when log cleaning is finished
55:  *                                or become LogCleaningAborted. Valid previous state is None.</li>
56:  * <li>3. LogCleaningAborted      : The cleaning abort is requested. In this state, it can become LogCleaningPaused(1).
57:  *                                Valid previous state is LogCleaningInProgress.</li>
58:  * <li>4-a. LogCleaningPaused(1)  : The cleaning is paused once. No log cleaning can be done in this state.
59:  *                                In this state, it can become None or LogCleaningPaused(2).
60:  *                                Valid previous state is None, LogCleaningAborted or LogCleaningPaused(2).</li>
61:  * <li>4-b. LogCleaningPaused(i)  : The cleaning is paused i times where i>= 2. No log cleaning can be done in this state.
62:  *                                In this state, it can become LogCleaningPaused(i-1) or LogCleaningPaused(i+1).
63:  *                                Valid previous state is LogCleaningPaused(i-1) or LogCleaningPaused(i+1).</li>
64:  * </ul>
65:  */
66: public class LogCleanerManager {
67:     public static final String OFFSET_CHECKPOINT_FILE = "cleaner-offset-checkpoint";
68: 
69:     private static final Logger LOG = LoggerFactory.getLogger("kafka.log.LogCleaner");
70: 
71:     private static final String UNCLEANABLE_PARTITIONS_COUNT_METRIC_NAME = "uncleanable-partitions-count";
72:     private static final String UNCLEANABLE_BYTES_METRIC_NAME = "uncleanable-bytes";
73:     private static final String MAX_DIRTY_PERCENT_METRIC_NAME = "max-dirty-percent";
74:     private static final String TIME_SINCE_LAST_RUN_MS_METRIC_NAME = "time-since-last-run-ms";
75: 
76:     // Visible for testing
77:     public static final Set<String> GAUGE_METRIC_NAME_NO_TAG = Set.of(MAX_DIRTY_PERCENT_METRIC_NAME, TIME_SINCE_LAST_RUN_MS_METRIC_NAME);
78: 
79:     // For compatibility, metrics are defined to be under `kafka.log.LogCleanerManager` class
80:     private final KafkaMetricsGroup metricsGroup = new KafkaMetricsGroup("kafka.log", "LogCleanerManager");
81: 
82:     /**
83:      * The set of logs currently being cleaned.
84:      */
85:     private final Map<TopicPartition, LogCleaningState> inProgress = new HashMap<>();
86: 
87:     /**
88:      * The set of uncleanable partitions (partitions that have raised an unexpected error during cleaning)
89:      * for each log directory.
90:      */
91:     private final Map<String, Set<TopicPartition>> uncleanablePartitions = new HashMap<>();
92: 
93:     /**
94:      * A global lock used to control all access to the in-progress set and the offset checkpoints.
95:      */
96:     private final Lock lock = new ReentrantLock();
97: 
