99:      * For coordinating the pausing and the cleaning of a partition.
100:      */
101:     private final Condition pausedCleaningCond = lock.newCondition();
102: 
103:     private final Map<String, List<Map<String, String>>> gaugeMetricNameWithTag = new HashMap<>();
104: 
105:     private final ConcurrentMap<TopicPartition, UnifiedLog> logs;
106: 
107:     /**
108:      * The offset checkpoints holding the last cleaned point for each log.
109:      */
110:     private volatile Map<File, OffsetCheckpointFile> checkpoints;
111: 
112:     private volatile double dirtiestLogCleanableRatio;
113:     private volatile long timeOfLastRun;
