115:     @SuppressWarnings({"this-escape"})
116:     public LogCleanerManager(
117:             List<File> logDirs,
118:             ConcurrentMap<TopicPartition, UnifiedLog> logs,
119:             LogDirFailureChannel logDirFailureChannel
120:     ) {
121:         this.logs = logs;
122:         checkpoints = logDirs.stream()
123:                 .collect(Collectors.toMap(
124:                         dir -> dir,
125:                         dir -> {
126:                             try {
127:                                 return new OffsetCheckpointFile(new File(dir, OFFSET_CHECKPOINT_FILE), logDirFailureChannel);
128:                             } catch (IOException e) {
129:                                 throw new RuntimeException(e);
130:                             }
131:                         }
132:                 ));
133: 
134:         registerMetrics(logDirs);
135:     }
