137:     private void registerMetrics(List<File> logDirs) {
138:         // gauges for tracking the number of partitions marked as uncleanable for each log directory
139:         for (File dir : logDirs) {
140:             Map<String, String> metricTag = Map.of("logDirectory", dir.getAbsolutePath());
141:             metricsGroup.newGauge(
142:                     UNCLEANABLE_PARTITIONS_COUNT_METRIC_NAME,
143:                     () -> inLock(lock, () -> uncleanablePartitions.getOrDefault(dir.getAbsolutePath(), Set.of()).size()),
144:                     metricTag
145:             );
146: 
147:             gaugeMetricNameWithTag
148:                     .computeIfAbsent(UNCLEANABLE_PARTITIONS_COUNT_METRIC_NAME, k -> new ArrayList<>())
149:                     .add(metricTag);
150:         }
151: 
152:         // gauges for tracking the number of uncleanable bytes from uncleanable partitions for each log directory
153:         for (File dir : logDirs) {
154:             Map<String, String> metricTag = Map.of("logDirectory", dir.getAbsolutePath());
155:             metricsGroup.newGauge(
156:                     UNCLEANABLE_BYTES_METRIC_NAME,
157:                     () -> inLock(lock, () -> {
158:                         Set<TopicPartition> partitions = uncleanablePartitions.get(dir.getAbsolutePath());
159: 
160:                         if (partitions == null) {
161:                             return 0;
162:                         } else {
163:                             Map<TopicPartition, Long> lastClean = allCleanerCheckpoints();
164:                             long now = Time.SYSTEM.milliseconds();
165:                             return partitions.stream()
166:                                     .mapToLong(tp -> {
167:                                         UnifiedLog log = logs.get(tp);
168:                                         if (log != null) {
169:                                             Optional<Long> lastCleanOffset = Optional.of(lastClean.get(tp));
170:                                             try {
171:                                                 OffsetsToClean offsetsToClean = cleanableOffsets(log, lastCleanOffset, now);
172:                                                 return calculateCleanableBytes(log, offsetsToClean.firstDirtyOffset(),
173:                                                         offsetsToClean.firstUncleanableDirtyOffset()).getValue();
174:                                             } catch (IOException e) {
175:                                                 throw new RuntimeException(e);
176:                                             }
177:                                         } else {
178:                                             return 0L;
179:                                         }
180:                                     }).sum();
181:                         }
182:                     }),
183:                     metricTag
184:             );
185: 
186:             gaugeMetricNameWithTag
187:                     .computeIfAbsent(UNCLEANABLE_BYTES_METRIC_NAME, k -> new ArrayList<>())
188:                     .add(metricTag);
189:         }
190: 
191:         // a gauge for tracking the cleanable ratio of the dirtiest log
192:         dirtiestLogCleanableRatio = 0.0;
193:         metricsGroup.newGauge(MAX_DIRTY_PERCENT_METRIC_NAME, () -> (int) (100 * dirtiestLogCleanableRatio));
194: 
195:         // a gauge for tracking the time since the last log cleaner run, in milliseconds
196:         timeOfLastRun = Time.SYSTEM.milliseconds();
197:         metricsGroup.newGauge(TIME_SINCE_LAST_RUN_MS_METRIC_NAME, () -> Time.SYSTEM.milliseconds() - timeOfLastRun);
198:     }
