204:     /**
205:      * @return the position processed for all logs.
206:      */
207:     public Map<TopicPartition, Long> allCleanerCheckpoints() {
208:         return inLock(lock, () -> checkpoints.values().stream()
209:                 .flatMap(checkpoint -> {
210:                     try {
211:                         return checkpoint.read().entrySet().stream();
212:                     } catch (KafkaStorageException e) {
213:                         LOG.error("Failed to access checkpoint file {} in dir {}",
214:                                 checkpoint.file().getName(), checkpoint.file().getParentFile().getAbsolutePath(), e);
215:                         return Stream.empty();
216:                     }
217:                 })
218:                 .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue)));
219:     }
