321:     /**
322:      * Find any logs that have compaction enabled. Mark them as being cleaned
323:      * Include logs without delete enabled, as they may have segments
324:      * that precede the start offset.
325:      */
326:     public Map<TopicPartition, UnifiedLog> deletableLogs() {
327:         return inLock(lock, () -> {
328:             Map<TopicPartition, UnifiedLog> toClean = logs.entrySet().stream()
329:                     .filter(entry -> {
330:                         TopicPartition topicPartition = entry.getKey();
331:                         UnifiedLog log = entry.getValue();
332:                         return !inProgress.containsKey(topicPartition) && log.config().compact &&
333:                                 !isUncleanablePartition(log, topicPartition);
334:                     })
335:                     .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
336:             toClean.forEach((partition, log) -> inProgress.put(partition, LogCleaningState.LOG_CLEANING_IN_PROGRESS));
337:             return toClean;
338:         });
339:     }
