341:     /**
342:      * Abort the cleaning of a particular partition, if it's in progress. This call blocks until the cleaning of
343:      * the partition is aborted.
344:      * This is implemented by first abortAndPausing and then resuming the cleaning of the partition.
345:      */
346:     public void abortCleaning(TopicPartition topicPartition) {
347:         inLock(lock, () -> {
348:             abortAndPauseCleaning(topicPartition);
349:             resumeCleaning(Set.of(topicPartition));
350:             return null;
351:         });
352:     }
353: 
354:     /**
355:      * Abort the cleaning of a particular partition if it's in progress, and pause any future cleaning of this partition.
356:      * This call blocks until the cleaning of the partition is aborted and paused.
357:      * <ol>
358:      * <li>If the partition is not in progress, mark it as paused.</li>
359:      * <li>Otherwise, first mark the state of the partition as aborted.</li>
360:      * <li>The cleaner thread checks the state periodically and if it sees the state of the partition is aborted, it
361:      *    throws a LogCleaningAbortedException to stop the cleaning task.</li>
362:      * <li>When the cleaning task is stopped, doneCleaning() is called, which sets the state of the partition as paused.</li>
363:      * <li>abortAndPauseCleaning() waits until the state of the partition is changed to paused.</li>
364:      * <li>If the partition is already paused, a new call to this function
365:      *    will increase the paused count by one.</li>
366:      * </ol>
367:      */
368:     public void abortAndPauseCleaning(TopicPartition topicPartition) {
369:         inLock(lock, () -> {
370:             LogCleaningState state = inProgress.get(topicPartition);
371: 
372:             if (state == null) {
373:                 inProgress.put(topicPartition, LogCleaningState.logCleaningPaused(1));
374:             } else if (state == LogCleaningState.LOG_CLEANING_IN_PROGRESS) {
375:                 inProgress.put(topicPartition, LogCleaningState.LOG_CLEANING_ABORTED);
376:             } else if (state instanceof LogCleaningState.LogCleaningPaused logCleaningPaused) {
377:                 inProgress.put(topicPartition, LogCleaningState.logCleaningPaused(logCleaningPaused.pausedCount() + 1));
378:             } else {
379:                 throw new IllegalStateException("Compaction for partition " + topicPartition +
380:                         " cannot be aborted and paused since it is in " + state + " state.");
381:             }
382: 
383:             while (!isCleaningInStatePaused(topicPartition)) {
384:                 try {
385:                     pausedCleaningCond.await(100, TimeUnit.MILLISECONDS);
386:                 } catch (InterruptedException e) {
387:                     throw new RuntimeException(e);
388:                 }
389:             }
390: 
391:             return null;
392:         });
393:     }
394: 
395:     /**
396:      * Resume the cleaning of paused partitions.
397:      * Each call of this function will undo one pause.
398:      */
399:     public void resumeCleaning(Set<TopicPartition> topicPartitions) {
400:         inLock(lock, () -> {
401:             topicPartitions.forEach(topicPartition -> {
402:                 LogCleaningState state = inProgress.get(topicPartition);
403: 
404:                 if (state == null) {
405:                     throw new IllegalStateException("Compaction for partition " + topicPartition + " cannot be resumed since it is not paused.");
406:                 }
407: 
408:                 if (state instanceof LogCleaningState.LogCleaningPaused logCleaningPaused) {
409:                     if (logCleaningPaused.pausedCount() == 1) {
410:                         inProgress.remove(topicPartition);
411:                     } else if (logCleaningPaused.pausedCount() > 1) {
412:                         inProgress.put(topicPartition, LogCleaningState.logCleaningPaused(logCleaningPaused.pausedCount() - 1));
413:                     }
414:                 } else {
415:                     throw new IllegalStateException("Compaction for partition " + topicPartition +
416:                             " cannot be resumed since it is in " + state + " state.");
417:                 }
418:             });
419: 
420:             return null;
421:         });
422:     }
