424:     /**
425:      * Check if the cleaning for a partition is in a particular state. The caller is expected to hold lock while making the call.
426:      */
427:     private boolean isCleaningInState(TopicPartition topicPartition, LogCleaningState expectedState) {
428:         LogCleaningState state = inProgress.get(topicPartition);
429: 
430:         if (state == null) {
431:             return false;
432:         } else {
433:             return state == expectedState;
434:         }
435:     }
