437:     /**
438:      * Check if the cleaning for a partition is paused. The caller is expected to hold lock while making the call.
439:      */
440:     private boolean isCleaningInStatePaused(TopicPartition topicPartition) {
441:         LogCleaningState state = inProgress.get(topicPartition);
442: 
443:         if (state == null) {
444:             return false;
445:         } else {
446:             return state instanceof LogCleaningState.LogCleaningPaused;
447:         }
448:     }
