451:      * Check if the cleaning for a partition is aborted. If so, throw an exception.
452:      */
453:     public void checkCleaningAborted(TopicPartition topicPartition) {
454:         inLock(lock, () -> {
455:             if (isCleaningInState(topicPartition, LogCleaningState.LOG_CLEANING_ABORTED)) {
456:                 throw new LogCleaningAbortedException();
457:             }
458:             return null;
459:         });
460:     }
