462:     /**
463:      * Update checkpoint file, adding or removing partitions if necessary.
464:      *
465:      * @param dataDir                The File object to be updated
466:      * @param partitionToUpdateOrAdd The [TopicPartition, Long] map entry to be updated. pass "Optional.empty" if doing remove, not add
467:      * @param partitionToRemove      The TopicPartition to be removed
468:      */
469:     public void updateCheckpoints(
470:             File dataDir,
471:             Optional<Map.Entry<TopicPartition, Long>> partitionToUpdateOrAdd,
472:             Optional<TopicPartition> partitionToRemove
473:     ) {
474:         inLock(lock, () -> {
475:             OffsetCheckpointFile checkpoint = checkpoints.get(dataDir);
476:             if (checkpoint != null) {
477:                 try {
478:                     Map<TopicPartition, Long> currentCheckpoint = checkpoint.read().entrySet().stream()
479:                             .filter(entry -> logs.containsKey(entry.getKey()))
480:                             .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
481: 
482:                     Map<TopicPartition, Long> updatedCheckpoint = new HashMap<>(currentCheckpoint);
483: 
484:                     // Remove the partition offset if present
485:                     partitionToRemove.ifPresent(updatedCheckpoint::remove);
486: 
487:                     // Update or add the partition offset if present
488:                     partitionToUpdateOrAdd.ifPresent(entry -> updatedCheckpoint.put(entry.getKey(), entry.getValue()));
489: 
490:                     // Write back the updated checkpoint
491:                     checkpoint.write(updatedCheckpoint);
492:                 } catch (KafkaStorageException e) {
493:                     LOG.error("Failed to access checkpoint file {} in dir {}",
494:                             checkpoint.file().getName(), checkpoint.file().getParentFile().getAbsolutePath(), e);
495:                 }
496:             }
497: 
498:             return null;
499:         });
500:     }
