502:     /**
503:      * Alter the checkpoint directory for the topicPartition, to remove the data in sourceLogDir, and add the data in destLogDir.
504:      */
505:     public void alterCheckpointDir(TopicPartition topicPartition, File sourceLogDir, File destLogDir) {
506:         inLock(lock, () -> {
507:             try {
508:                 Optional<Long> offsetOpt = Optional.ofNullable(checkpoints.get(sourceLogDir))
509:                         .flatMap(checkpoint -> Optional.ofNullable(checkpoint.read().get(topicPartition)));
510: 
511:                 offsetOpt.ifPresent(offset -> {
512:                     LOG.debug("Removing the partition offset data in checkpoint file for '{}' from {} directory.",
513:                             topicPartition, sourceLogDir.getAbsoluteFile());
514:                     updateCheckpoints(sourceLogDir, Optional.empty(), Optional.of(topicPartition));
515: 
516:                     LOG.debug("Adding the partition offset data in checkpoint file for '{}' to {} directory.",
517:                             topicPartition, destLogDir.getAbsoluteFile());
518:                     updateCheckpoints(destLogDir, Optional.of(Map.entry(topicPartition, offset)), Optional.empty());
519:                 });
520:             } catch (KafkaStorageException e) {
521:                 LOG.error("Failed to access checkpoint file in dir {}", sourceLogDir.getAbsolutePath(), e);
522:             }
523: 
524:             Set<TopicPartition> logUncleanablePartitions = uncleanablePartitions.getOrDefault(sourceLogDir.toString(), Collections.emptySet());
525:             if (logUncleanablePartitions.contains(topicPartition)) {
526:                 logUncleanablePartitions.remove(topicPartition);
527:                 markPartitionUncleanable(destLogDir.toString(), topicPartition);
528:             }
529: 
530:             return null;
531:         });
532:     }
