28: /**
29:  * A hash table used for de-duplicating the log. This hash table uses a cryptographically secure hash of the key as a proxy for the key
30:  * for comparisons and to save space on object overhead. Collisions are resolved by probing. This hash table does not support deletes.
31:  */
32: public class SkimpyOffsetMap implements OffsetMap {
33: 
34:     /**
35:      * The number of bytes of space each entry uses (the number of bytes in the hash plus an 8 byte offset)
36:      */
37:     public final int bytesPerEntry;
38: 
39:     private final ByteBuffer bytes;
40: 
41:     /* the hash algorithm instance to use */
42:     private final MessageDigest digest;
43: 
44:     /* the number of bytes for this hash algorithm */
45:     private final int hashSize;
46: 
47:     /**
48:      * The maximum number of entries this map can contain
49:      */
50:     private final int slots;
51: 
52:     /* cache some hash buffers to avoid reallocating each time */
53:     private final byte[] hash1;
54:     private final byte[] hash2;
55: 
56:     /* number of entries put into the map */
57:     private int entries = 0;
58: 
59:     /* number of lookups on the map */
60:     private long lookups = 0L;
61: 
62:     /* the number of probes for all lookups */
63:     private long probes = 0L;
64: 
65:     /* the latest offset written into the map */
66:     private long lastOffset = -1L;
67: 
68:     /**
69:      * Create an instance of SkimplyOffsetMap with the default hash algorithm (MD5).
70:      *
71:      * @param memory The amount of memory this map can use
72:      */
73:     public SkimpyOffsetMap(int memory) throws NoSuchAlgorithmException {
74:         this(memory, "MD5");
75:     }
76: 
77:     /**
78:      * Create an instance of SkimpyOffsetMap.
79:      *
80:      * @param memory The amount of memory this map can use
81:      * @param hashAlgorithm The hash algorithm instance to use: MD2, MD5, SHA-1, SHA-256, SHA-384, SHA-512
82:      */
83:     public SkimpyOffsetMap(int memory, String hashAlgorithm) throws NoSuchAlgorithmException {
84:         this.bytes = ByteBuffer.allocate(memory);
85: 
86:         this.digest = MessageDigest.getInstance(hashAlgorithm);
87: 
88:         this.hashSize = digest.getDigestLength();
89:         this.bytesPerEntry = hashSize + 8;
90:         this.slots = memory / bytesPerEntry;
91: 
92:         this.hash1 = new byte[hashSize];
93:         this.hash2 = new byte[hashSize];
94:     }
95: 
96:     @Override
97:     public int slots() {
98:         return slots;
99:     }
100: 
101:     /**
102:      * Get the offset associated with this key.
103:      * @param key The key
104:      * @return The offset associated with this key or -1 if the key is not found
105:      */
106:     @Override
107:     public long get(ByteBuffer key) throws DigestException {
108:         ++lookups;
109:         hashInto(key, hash1);
110:         // search for the hash of this key by repeated probing until we find the hash we are looking for or we find an empty slot
111:         int attempt = 0;
112:         //we need to guard against attempt integer overflow if the map is full
113:         //limit attempt to number of slots once positionOf(..) enters linear search mode
114:         int maxAttempts = slots + hashSize - 4;
115:         do {
116:             if (attempt >= maxAttempts)
117:                 return -1L;
118:             int pos = positionOf(hash1, attempt);
119:             bytes.position(pos);
120:             if (isEmpty(pos))
121:                 return -1L;
122:             bytes.get(hash2);
123:             ++attempt;
124:         } while (!Arrays.equals(hash1, hash2));
125:         return bytes.getLong();
126:     }
127: 
128:     /**
129:      * Associate this offset to the given key.
130:      * @param key The key
131:      * @param offset The offset
132:      */
133:     @Override
134:     public void put(ByteBuffer key, long offset) throws DigestException {
135:         if (entries >= slots)
136:             throw new IllegalArgumentException("Attempted to add a new entry to a full offset map, "
137:                 + "entries: " + entries + ", slots: " + slots);
138: 
139:         ++lookups;
140:         hashInto(key, hash1);
141: 
142:         // probe until we find the first empty slot
143:         int attempt = 0;
144:         int pos = positionOf(hash1, attempt);
145:         while (!isEmpty(pos)) {
146:             bytes.position(pos);
147:             bytes.get(hash2);
148:             if (Arrays.equals(hash1, hash2)) {
149:                 // we found an existing entry, overwrite it and return (size does not change)
150:                 bytes.putLong(offset);
151:                 lastOffset = offset;
152:                 return;
153:             }
154:             ++attempt;
155:             pos = positionOf(hash1, attempt);
156:         }
157: 
158:         // found an empty slot, update it - size grows by 1
159:         bytes.position(pos);
160:         bytes.put(hash1);
161:         bytes.putLong(offset);
162:         lastOffset = offset;
163:         ++entries;
164:     }
165: 
166:     @Override
167:     public void updateLatestOffset(long offset) {
168:         this.lastOffset = offset;
169:     }
170: 
171:     /**
172:      * Change the salt used for key hashing making all existing keys unfindable.
173:      */
174:     @Override
175:     public void clear() {
176:         this.entries = 0;
177:         this.lookups = 0L;
178:         this.probes = 0L;
179:         this.lastOffset = -1L;
180:         Arrays.fill(bytes.array(), bytes.arrayOffset(), bytes.arrayOffset() + bytes.limit(), (byte) 0);
181:     }
182: 
183:     /**
184:      * The number of entries put into the map (note that not all may remain)
185:      */
186:     @Override
187:     public int size() {
188:         return entries;
189:     }
190: 
191:     /**
192:      * The latest offset put into the map
193:      */
194:     @Override
195:     public long latestOffset() {
196:         return lastOffset;
197:     }
